import numpy as npfrom scipy.stats import norm#parametersS0 = 3sigma = 0.3T = 1K = 4r = 0.03x0 = np.log(S0/K)mu = (r - 0.5*sigma**2)#truncation range for COS method (eq 49)c1 = x0 + mu* Tc2 = T*sigma**2c4 = 0L = 10a = c1-L*np.sqrt(c2 + np.sqrt(c4))b = c1+L*np.sqrt(c2 + np.sqrt(c4))def phi_BS(w, x,r, sigma, T):    """    we compute the characteristic function of y = ln(S_T/K) under Q, which can be obtained from eq (31) in the COS paper    """    mu_y  = x + (r - 0.5*sigma**2) * T    var_y = sigma**2 * T    return np.exp(1j*w*mu_y - 0.5*var_y*w**2)def phi_k(k,a,b,c,d):    """    we compute the function phi_k from 2(c)    """    wk = k*np.pi/(b-a)    return (1/wk)*(np.cos(wk*(c - a)) - np.cos(wk*(d - a)))def chi_k(k,a,b,c,d):    """    we compute the function chi_k from 2(c)    """    wk = k*np.pi/(b-a)    def term(y):        return np.exp(y) * (np.sin(wk*(y - a)) - wk*np.cos(wk*(y - a))) / (1.0 + wk**2)    return term(d)-term(c)def V_k_put(a, b, K, ks):    """    we compute the Fourier-sine coefficients for a put option 2(c)    """    return (2.0*K / (b-a)) * (-chi_k(ks, a, b, a, 0.0) + phi_k(ks, a, b, a, 0.0))def sin_put_price(N, S0, K, r, sigma, T, a, b):    """    we compute the SIN method price of a European put option, which is the formula v = v_3 from 2(c)    """        ks    = np.arange(1, N+1, dtype=float) #generate the summation indexes    wk = ks * np.pi / (b-a)    cf_part = np.imag(phi_BS(wk, x0, r, sigma, T) * np.exp(-1j * wk * a)) #compute the imaginary part, which involves the density of Black-Scholes model    Vk = V_k_put(a, b, K, ks)    return np.exp(-r*T) * np.dot(cf_part, Vk)def bs_put(S0, K, r, sigma, T):    """    we compute the analytical solution for the Black-Scholes put price    """    d1 = (np.log(S0/K) + (r + 0.5*sigma**2)*T) / (sigma*np.sqrt(T))    d2 = d1 - sigma * np.sqrt(T)    return K * np.exp(-r*T)*norm.cdf(-d2) - S0*norm.cdf(-d1)Price_BS = bs_put(S0, K, r, sigma, T)print(f"Black-Scholes analytical price: {Price_BS:.10f}\n")print(f"{'N':>5}  {'SIN price':>16}  {'|SIN - BS|':>14}")print("-"*40)for N in [4,8,16, 32, 64, 128, 256, 512, 1024]:    Price_sin = sin_put_price(N, S0, K, r, sigma, T, a, b)    err   = abs(Price_sin - Price_BS)    print(f"{N:>5}  {Price_sin:>16.10f}  {err:>14.4e}")